class Account:
    def __init__(self, owner, balance=0):
        self.owner = owner
        self._balance = balance

    def deposit(self, amt):
        self._balance += amt
        return self._balance

acc = Account("Ada", 100)
print(acc.deposit(50))     # 150

class Animal:
    def __init__(self, name): self.name = name
    def speak(self): return "..."

class Dog(Animal):
    def __init__(self, name, breed):
        super().__init__(name)     # reuse parent setup
        self.breed = breed
    def speak(self): return "Woof"  # override

print(Dog("Rex", "Lab").speak())   # Woof

class Point:
    def __init__(self, x, y): self.x, self.y = x, y
    def __repr__(self): return f"Point({self.x}, {self.y})"
    def __eq__(self, other):
        return (self.x, self.y) == (other.x, other.y)

print(Point(1, 2))                  # Point(1, 2)
print(Point(1, 2) == Point(1, 2))   # True

class Date:
    def __init__(self, y, m, d):
        self.y, self.m, self.d = y, m, d

    @classmethod
    def from_string(cls, s):        # cls = the class itself
        y, m, d = map(int, s.split("-"))
        return cls(y, m, d)

d = Date.from_string("2026-06-02")
print(d.y, d.m, d.d)               # 2026 6 2

